--sp_helptext [SegCredMoraSuc]

-- --sp_helptext [pCsOpCaCubSucursalMov]  
  
CREATE procedure [dbo].[SegCredMoraSuc] @zona varchar(5)  
as  
--set nocount on--off  
  
--declare @zona varchar(5)  
--set @zona='Z16'  
  
declare @fecfin smalldatetime  
select @fecfin=fechaconsolidacion from vcsfechaconsolidacion  
  
declare @fecini smalldatetime  
select @fecini=dateadd(day,(-1)*day(@fecfin) + 1 ,@fecfin)  
  
declare @sucursales table(codigo varchar(4))  
insert into @sucursales  
select codoficina  
from tcloficinas  
where zona=@zona  
   
 CREATE TABLE #ptmos (codprestamo varchar (25), codoficina varchar(5), nrodiasatrasoini int, saldocapitalini money)  
 insert into #ptmos   
 Select distinct codprestamo, codoficina, nrodiasatraso, saldocapital  
 from tcscartera with (nolock)  
 where fecha = @fecini   
 and codoficina in(select codigo from @sucursales) 
 and codprestamo in 
